## 3. Build script (`setup.py`)

```python
# ---------------------------------------------------------------
#  setup.py
# ---------------------------------------------------------------
import pathlib
import sys
import sysconfig

from setuptools import setup, Extension
from setuptools.command.build_ext import build_ext

# pybind11 provides the include path via a helper function
import pybind11

# ---------------------------------------------------------------
#  Helper class – makes the extension compile on all major OSes
# ---------------------------------------------------------------
class get_pybind_include(object):
    """Helper class to determine the pybind11 include path"""
    def __str__(self):
        return pybind11.get_include()


ext_modules = [
    Extension(
        "pcapng",
        ["pcapng_bindings.cpp"],
        include_dirs=[
            # Path to pybind11 headers
            get_pybind_include(),
        ],
        language="c++",
        # C++14 is enough for the example; adjust if your real lib needs newer
        extra_compile_args=["-std=c++14"] if sys.platform != "win32" else [],
    ),
]

# ---------------------------------------------------------------
#  Setup call
# ---------------------------------------------------------------
setup(
    name="pcapng",
    version="0.1.0",
    author="Your Name",
    description="Python bindings for libpcapng (demo)",
    long_description="See the source file for a full example of the API.",
    ext_modules=ext_modules,
    cmdclass={"build_ext": build_ext},
    zip_safe=False,
)
```

Run the build once:

```bash
$ pip install .
# or, for a quick test:
$ python setup.py build_ext --inplace
```

You will get a compiled shared object (`pcapng.cpython-*.so` on Linux/macOS, `pcapng.pyd` on Windows) that you can import directly.

