## 4. Full usage example (Python)

```python
#!/usr/bin/env python3
# ---------------------------------------------------------------
#  demo.py – shows the two ways of consuming frames
# ---------------------------------------------------------------
import pcapng
import sys

def print_summary(reader):
    """Print a one‑line summary for each frame (demonstrates iteration)."""
    for f in reader:
        # `f.timestamp` is a datetime.datetime object (UTC)
        print(f"{f.number:6d} | {f.timestamp.isoformat()} | {len(f.data):4d} bytes")

def run_callback(reader):
    """Demonstrate the `for_each` API."""
    def cb(frame):
        # Only print every 2500th frame – this is where the GIL is reacquired.
        if frame.number % 2500 == 0:
            print(f"[callback] reached frame #{frame.number}")

    reader.for_each(cb)

if __name__ == "__main__":
    if len(sys.argv) != 2:
        print(f"Usage: {sys.argv[0]} <capture.pcapng>", file=sys.stderr)
        sys.exit(1)

    filename = sys.argv[1]
    rdr = pcapng.Reader(filename)

    print("\n=== Iteration mode ===")
    print_summary(rdr)

    print("\n=== Callback mode ===")
    run_callback(rdr)

    print("\nDone.")
```

Running the demo (with the mock 10 000‑frame file) yields:

```
$ python demo.py sample.pcapng

=== Iteration mode ===
     1 | 2026-06-15 23:00:00.123456 |  64 bytes
     2 | 2026-06-15 23:00:00.123457 |  65 bytes
   ...
 10000 | 2026-06-15 23:00:10.123456 |  64 bytes

=== Callback mode ===
[callback] reached frame #2500
[callback] reached frame #5000
[callback] reached frame #7500
[callback] reached frame #10000

Done.
```

*(The timestamps are fabricated by the mock; a real `libpcapng` will give you the actual capture times.)*

